        if isinstance(data, dict):
            if "relationships_following" in data:
                data = data["relationships_following"]
            else:
                data = list(data.values())[0] if data else []

        if isinstance(data, list):
            for item in data:
                follow_entry = {}

                if isinstance(item, dict):
                    if "string_list_data" in item:
